import boto3
from moto import mock_ecs

@mock_ecs
def test_edge_cases():
    client = boto3.client('ecs', region_name='us-east-1')

    # Create cluster with initial tags
    res = client.create_cluster(
        clusterName='foo',
        tags=[{'key': 'initial', 'value': 'tag'}]
    )
    arn = res['cluster']['clusterArn']

    # Test 1: Add multiple tags at once
    client.tag_resource(resourceArn=arn, tags=[
        {'key': 'tag1', 'value': 'value1'},
        {'key': 'tag2', 'value': 'value2'}
    ])

    # Test 2: Add a tag to a resource that already has tags
    client.tag_resource(resourceArn=arn, tags=[
        {'key': 'tag3', 'value': 'value3'}
    ])

    # Test 3: Override an existing tag
    client.tag_resource(resourceArn=arn, tags=[
        {'key': 'tag1', 'value': 'new_value'}
    ])

    # Verify final state
    response = client.list_tags_for_resource(resourceArn=arn)
    print("Final tags:", response['tags'])

test_edge_cases()
